diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..8c9f8b99f152 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7885,6 +7885,7 @@ static Instruction *foldFCmpFNegCommonOp(FCmpInst &I) {
   return new FCmpInst(Pred, Op0, Zero, "", &I);
 }

+
 Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   bool Changed = false;

@@ -8065,7 +8066,51 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
                   cast<LoadInst>(LHSI), GEP, GV, I))
             return Res;
       break;
-  }
+    case Instruction::Select:
+      // Handle patterns like:
+      //   fcmp oeq (select (fcmp oge X, 0), X, (fneg X)), 0 -> fcmp oeq X, 0
+      // This works because the select computes abs(X) or -abs(X), and
+      // abs(X) == 0 iff X == 0.
+      if (I.isEquality() && match(RHSC, m_AnyZeroFP())) {
+        auto *SI = cast<SelectInst>(LHSI);
+        Value *Cond = SI->getCondition();
+        Value *TrueVal = SI->getTrueValue();
+        Value *FalseVal = SI->getFalseValue();
+
+        CmpInst::Predicate CondPred;
+        Value *X;
+        if (match(Cond, m_FCmp(CondPred, m_Value(X), m_AnyZeroFP()))) {
+          // Check if the condition is a sign check (X >= 0, X < 0, etc.).
+          bool IsSignTest = false;
+          switch (CondPred) {
+          case FCmpInst::FCMP_OGT:
+          case FCmpInst::FCMP_OGE:
+          case FCmpInst::FCMP_UGT:
+          case FCmpInst::FCMP_UGE:
+          case FCmpInst::FCMP_OLT:
+          case FCmpInst::FCMP_OLE:
+          case FCmpInst::FCMP_ULT:
+          case FCmpInst::FCMP_ULE:
+            IsSignTest = true;
+            break;
+          default:
+            break;
+          }
+
+          if (IsSignTest) {
+            // Check if the select operands are X and -X.
+            bool TrueIsX = (TrueVal == X);
+            bool FalseIsX = (FalseVal == X);
+            bool TrueIsNegX = match(TrueVal, m_FNeg(m_Specific(X)));
+            bool FalseIsNegX = match(FalseVal, m_FNeg(m_Specific(X)));
+
+            if ((TrueIsX && FalseIsNegX) || (TrueIsNegX && FalseIsX))
+              return new FCmpInst(Pred, X, RHSC, "", &I);
+          }
+        }
+      }
+      break;
+    }
   }

   if (Instruction *R = foldFabsWithFcmpZero(I, *this))
@@ -8180,3 +8225,4 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {

   return Changed ? &I : nullptr;
 }
+

